from typing import List
from collections import Counter

class Solution:
    def continuousSubarrays(self, nums: List[int]) -> int:
        # Maintain a sliding window [l..r] such that max(nums[l..r]) - min(nums[l..r]) <= 2.
        # Condition "for each pair" is equivalent to max-min <= 2.
        l = 0
        ans = 0

        min_deque = []  # stores indices, increasing by value
        max_deque = []  # stores indices, decreasing by value

        def push_min(i):
            while min_deque and nums[min_deque[-1]] > nums[i]:
                min_deque.pop()
            min_deque.append(i)

        def push_max(i):
            while max_deque and nums[max_deque[-1]] < nums[i]:
                max_deque.pop()
            max_deque.append(i)

        for r, x in enumerate(nums):
            push_min(r)
            push_max(r)

            # shrink until condition holds
            while nums[max_deque[0]] - nums[min_deque[0]] > 2:
                if min_deque[0] == l:
                    min_deque.pop(0)
                if max_deque[0] == l:
                    max_deque.pop(0)
                l += 1

            # all subarrays ending at r and starting in [l..r] are valid
            ans += r - l + 1

        return ans
