        # 0 <= |a-b| <= 2, i.e., max(nums_sub) - min(nums_sub) <= 2.
        # Count subarrays satisfying this using a sliding window and deques for min/max.

        n = len(nums)
        minq = []  # increasing values' indices
        maxq = []  # decreasing values' indices

        def push_min(i):
            while minq and nums[minq[-1]] > nums[i]:
                minq.pop()
            minq.append(i)

        def push_max(i):
            while maxq and nums[maxq[-1]] < nums[i]:
                maxq.pop()
            maxq.append(i)

        res = 0
        left = 0
        for right in range(n):
            push_min(right)
            push_max(right)

            while nums[maxq[0]] - nums[minq[0]] > 2:
                if minq[0] == left:
                    minq.pop(0)
                if maxq[0] == left:
                    maxq.pop(0)
                left += 1

            res += right - left + 1

        return res
