        max_dq = []  # stores indices with decreasing nums[]

        def push_min(i: int):
            while min_dq and nums[min_dq[-1]] >= nums[i]:
                min_dq.pop()
            min_dq.append(i)

        def push_max(i: int):
            while max_dq and nums[max_dq[-1]] <= nums[i]:
                max_dq.pop()
            max_dq.append(i)

        ans = 0
        l = 0
        for r in range(n):
            push_min(r)
            push_max(r)

            while nums[max_dq[0]] - nums[min_dq[0]] > 2:
                if min_dq[0] == l:
                    min_dq.pop(0)
                if max_dq[0] == l:
                    max_dq.pop(0)
                l += 1

            ans += r - l + 1

        return ans
